const state = { selectedDepartment:'88' };
const departments = PRICING.departments.slice().sort((a,b)=>a.code.localeCompare(b.code,'fr'));
const departmentMap = Object.fromEntries(departments.map(d=>[d.code,d]));
const svg = document.getElementById('mapSvg');
const mapWrap = document.getElementById('mapWrap');
const tip = document.getElementById('mapTip');
const selectedDeptPill = document.getElementById('selectedDeptPill');
const mapFooterSelected = document.getElementById('mapFooterSelected');
const parcelsNode = document.getElementById('parcels');
const reasonList = document.getElementById('reasonList');
const searchInput = document.getElementById('searchInput');
const searchList = document.getElementById('searchList');
const serviceNote = document.getElementById('serviceNote');

const resultEls = {
  title: document.getElementById('carrierTitle'),
  note: document.getElementById('carrierNote'),
  badge: document.getElementById('carrierBadge'),
  transportTtc: document.getElementById('transportTtc'),
  sellerTtc: document.getElementById('sellerTtc'),
  actualWeight: document.getElementById('actualWeight'),
  chargeableWeight: document.getElementById('chargeableWeight'),
  baseHt: document.getElementById('baseHt'),
  fixedHt: document.getElementById('fixedHt'),
  energyHt: document.getElementById('energyHt'),
  extraHt: document.getElementById('extraHt')
};

const toggleButtons = Array.from(document.querySelectorAll('.toggle-btn'));

function setToggleState(button, expanded) {
  const target = document.getElementById(button.dataset.target);
  if (!target) return;
  button.setAttribute('aria-expanded', expanded ? 'true' : 'false');
  button.textContent = expanded ? '−' : '+';
  target.hidden = !expanded;
}

function collapseResultSections() {
  toggleButtons.forEach(button => setToggleState(button, false));
}

toggleButtons.forEach(button => {
  setToggleState(button, false);
  button.addEventListener('click', () => {
    const expanded = button.getAttribute('aria-expanded') === 'true';
    setToggleState(button, !expanded);
  });
});


function renderMap() {
  const frag = document.createDocumentFragment();
  MAP_DATA.forEach(item => {
    const dept = departmentMap[item.code];
    if (!dept) return;

    const path = document.createElementNS('http://www.w3.org/2000/svg','path');
    path.setAttribute('d', item.d);
    path.setAttribute('class', 'dept');
    path.dataset.code = item.code;
    path.dataset.name = dept.name;
    path.addEventListener('click', () => selectDepartment(item.code));
    path.addEventListener('mouseenter', (e) => showTip(e, `${item.code} — ${dept.name}`));
    path.addEventListener('mousemove', moveTip);
    path.addEventListener('mouseleave', hideTip);
    frag.appendChild(path);

    const text = document.createElementNS('http://www.w3.org/2000/svg','text');
    text.setAttribute('x', item.cx);
    text.setAttribute('y', item.cy);
    text.setAttribute('class', 'dept-label');
    text.dataset.code = item.code;
    text.textContent = item.code;
    frag.appendChild(text);
  });
  svg.appendChild(frag);
  syncSelectedDept();
}

function selectDepartment(code) {
  state.selectedDepartment = code;
  const label = `${code} — ${departmentMap[code].name}`;
  selectedDeptPill.textContent = label;
  mapFooterSelected.textContent = `Département sélectionné : ${label}`;
  searchInput.value = label;
  syncSelectedDept();
  closeSearch();
}

function syncSelectedDept() {
  document.querySelectorAll('.dept').forEach(el => el.classList.toggle('is-selected', el.dataset.code === state.selectedDepartment));
  document.querySelectorAll('.dept-label').forEach(el => el.classList.toggle('is-selected', el.dataset.code === state.selectedDepartment));
}

function showTip(event, text) { tip.textContent = text; tip.classList.add('is-visible'); moveTip(event); }
function moveTip(event) {
  const rect = mapWrap.getBoundingClientRect();
  tip.style.left = `${event.clientX - rect.left}px`;
  tip.style.top = `${event.clientY - rect.top}px`;
}
function hideTip() { tip.classList.remove('is-visible'); }

function formatCurrency(v) { return new Intl.NumberFormat('fr-FR', { style:'currency', currency:'EUR' }).format(v); }
function formatNumber(v, d=2) { return new Intl.NumberFormat('fr-FR', { minimumFractionDigits:d, maximumFractionDigits:d }).format(v); }
function round2(v) { return Math.round(v*100)/100; }
function toNumber(v) { const n = Number.parseFloat(String(v).replace(',', '.')); return Number.isFinite(n) ? n : 0; }

function addParcel(prefill={length:'',width:'',height:'',weight:''}) {
  const card = document.createElement('div');
  card.className = 'parcel';
  card.innerHTML = `
    <div class="parcel-head">
      <h3 class="parcel-title">Colis</h3>
      <button class="icon-btn" type="button" title="Supprimer">×</button>
    </div>
    <div class="parcel-grid">
      <label class="label">Longueur (cm)<input class="input" inputmode="decimal" data-field="length" value="${prefill.length}"></label>
      <label class="label">Largeur (cm)<input class="input" inputmode="decimal" data-field="width" value="${prefill.width}"></label>
      <label class="label">Hauteur (cm)<input class="input" inputmode="decimal" data-field="height" value="${prefill.height}"></label>
      <label class="label">Poids (kg)<input class="input" inputmode="decimal" data-field="weight" value="${prefill.weight}"></label>
    </div>
  `;
  card.querySelector('.icon-btn').addEventListener('click', () => {
    if (parcelsNode.children.length === 1) return toast('Il faut garder au moins un colis.');
    card.remove();
    renumberParcels();
  });
  parcelsNode.appendChild(card);
  renumberParcels();
}

function renumberParcels() { [...parcelsNode.children].forEach((el,i)=>el.querySelector('.parcel-title').textContent = `Colis ${i+1}`); }

function readParcels() {
  const parcels = [...parcelsNode.children].map(card => Object.fromEntries([...card.querySelectorAll('[data-field]')].map(input => [input.dataset.field, toNumber(input.value)])));
  if (!parcels.length) throw new Error('Ajoute au moins un colis.');
  if (parcels.some(p => !p.length || !p.width || !p.height || !p.weight)) throw new Error('Merci de remplir toutes les dimensions et tous les poids.');
  return parcels;
}

function findGeodisBand(weight) {
  const w = Math.ceil(weight);
  if (w <= 4) return '0-4';
  if (w <= 9) return '5-9';
  if (w <= 14) return '10-14';
  if (w <= 19) return '15-19';
  if (w <= 29) return '20-29';
  if (w <= 39) return '30-39';
  if (w <= 49) return '40-49';
  if (w <= 59) return '50-59';
  if (w <= 69) return '60-69';
  if (w <= 79) return '70-79';
  if (w <= 89) return '80-89';
  if (w <= 99) return '90-99';
  if (w <= 199) return '100-199';
  if (w <= 299) return '200-299';
  if (w <= 499) return '300-499';
  return '500-1000';
}

function computeGeodisBase(prices, actualWeight) {
  const roundedWeight = Math.ceil(actualWeight);
  const band = findGeodisBand(roundedWeight);
  const rate = prices[band];
  if (rate == null) return { band, baseHt: null, billedWeight: roundedWeight };
  if (roundedWeight <= 99) {
    return { band, baseHt: rate, billedWeight: roundedWeight };
  }
  const billedWeight = Math.ceil(roundedWeight / 10) * 10;
  return {
    band,
    baseHt: round2(rate * (billedWeight / 100)),
    billedWeight
  };
}

function buildManualResult(note, actualWeight, chargeableWeight, reasons) {
  return {
    carrier:'Devis manuel', badge:'manual', note,
    transportTtc:null, sellerTtc:null, baseHt:null,
    fixedHt:null, energyHt:null, extraHt:null,
    actualWeight, chargeableWeight, reasons
  };
}

function computeQuote(parcels) {
  const { settings, tables } = PRICING;
  const reasons = [];
  let actualWeight = 0, chargeableWeight = 0, totalVolume = 0, dpdEligible = true, geodisEligible = true, heavyCount = 0;

  parcels.forEach((parcel, index) => {
    const dims = [parcel.length, parcel.width, parcel.height].sort((a,b)=>b-a);
    const [length, width, height] = dims;
    const girth = length + 2 * (width + height);
    const volumetric = (length * width * height) / settings.dpd.volumetricDivisor;
    const taxable = Math.max(parcel.weight, volumetric);
    const volume = (length * width * height) / 1000000;

    actualWeight += parcel.weight;
    chargeableWeight += taxable;
    totalVolume += volume;

    reasons.push(`Colis ${index+1} : ${formatNumber(length,1)} × ${formatNumber(width,1)} × ${formatNumber(height,1)} cm · réel ${formatNumber(parcel.weight,2)} kg · taxable ${formatNumber(taxable,2)} kg`);
    if (length > settings.dpd.maxLengthCm || girth > settings.dpd.maxGirthCm || parcel.weight > settings.dpd.maxActualKgPerParcel) dpdEligible = false;
    if (parcel.weight > 20 && parcel.weight <= 30) heavyCount += 1;

    if (
      parcel.weight > settings.geodis.paletteMaxKg ||
      length > 400 ||
      height > 200
    ) geodisEligible = false;
  });

  if (actualWeight > settings.dpd.maxActualKgPerParcel) dpdEligible = false;
  if (actualWeight > settings.geodis.maxTotalKg || totalVolume > settings.geodis.maxVolumeM3) geodisEligible = false;

  const code = state.selectedDepartment;
  const label = `${code} — ${departmentMap[code].name}`;
  const geodisDepartment = tables.geodisByDepartment[code] || null;

    if (code === '2A' || code === '2B') {
    return buildManualResult(`Corse sélectionnée (${label}) : devis manuel.`, actualWeight, chargeableWeight, [...reasons, 'La Corse reste hors calcul automatique dans cette version.']);
  }

  const dpdWeight = Math.min(30, Math.max(1, Math.ceil(chargeableWeight)));
  const dpdRow = tables.dpd.find(item => item.maxKg === dpdWeight);

  if (dpdEligible && dpdRow && dpdRow.predict != null) {
    const baseHt = dpdRow.predict;
    const fixedHt = settings.dpd.fixedFeeHt;
    const extraHt = heavyCount * settings.dpdHeavyParcelSupplementHt;
    const energyHt = round2(baseHt * settings.dpd.fuelPercent / 100);
    const transportTtc = round2((baseHt + fixedHt + extraHt + energyHt) * (1 + settings.vatPercent/100));
    const sellerTtc = round2(transportTtc + settings.sellerMarkupTtc);
    return {
      carrier:'DPD', badge:'dpd', note:`DPD retenu automatiquement pour ${label}.`,
      transportTtc, sellerTtc, baseHt, fixedHt, energyHt, extraHt,
      actualWeight, chargeableWeight,
      reasons:[...reasons, 'Service : Livraison domicile.', `Tranche DPD utilisée : ${dpdWeight} kg.`, heavyCount ? `Supplément colis > 20 kg : ${heavyCount}.` : 'Aucun supplément colis > 20 kg.']
    };
  }

  if (geodisEligible && geodisDepartment) {
    const geodisCalc = computeGeodisBase(geodisDepartment.prices, actualWeight);
    if (geodisCalc.baseHt == null) {
      return buildManualResult(`Aucun tarif GEODIS intégré pour ${label}.`, actualWeight, chargeableWeight, [...reasons, 'Le barème GEODIS chargé ne couvre pas cette saisie.']);
    }
    const baseHt = geodisCalc.baseHt;
    const fixedHt = settings.geodis.fixedFeeHt;
    const energyHt = round2(baseHt * settings.geodis.energyPercent / 100);
    const extraHt = 0;
    const transportTtc = round2((baseHt + fixedHt + energyHt) * (1 + settings.vatPercent/100));
    const sellerTtc = round2(transportTtc + settings.sellerMarkupTtc);
    return {
      carrier:'GEODIS', badge:'geodis', note:`GEODIS retenu automatiquement pour ${label}.`,
      transportTtc, sellerTtc, baseHt, fixedHt, energyHt, extraHt,
      actualWeight, chargeableWeight,
      reasons:[
        ...reasons,
        'Service : Livraison domicile.',
        actualWeight <= 99
          ? `Tranche GEODIS utilisée : ${geodisCalc.band} kg (forfait).`
          : `Tranche GEODIS utilisée : ${geodisCalc.band} kg, facturation aux 100 kg avec poids arrondi à ${formatNumber(geodisCalc.billedWeight,0)} kg.`,
        `Volume total indicatif : ${formatNumber(totalVolume,3)} m³.`,
        'Logique GEODIS alignée sur l’ancien outil : bascule automatique dès que DPD ne passe plus.'
      ]
    };
  }

  return buildManualResult(`Aucun calcul automatique fiable pour ${label}.`, actualWeight, chargeableWeight, [...reasons, 'DPD et GEODIS sont hors limites sur cette saisie.']);
}

function renderResult(result) {
  resultEls.title.textContent = result.carrier;
  resultEls.note.textContent = result.note;
  resultEls.badge.textContent = result.carrier;
  resultEls.badge.className = `badge ${result.badge}`;
  resultEls.transportTtc.textContent = result.transportTtc == null ? '—' : formatCurrency(result.transportTtc);
  resultEls.sellerTtc.textContent = result.sellerTtc == null ? '—' : formatCurrency(result.sellerTtc);
  resultEls.actualWeight.textContent = `${formatNumber(result.actualWeight,2)} kg`;
  resultEls.chargeableWeight.textContent = `${formatNumber(result.chargeableWeight,2)} kg`;
  resultEls.baseHt.textContent = result.baseHt == null ? '—' : formatCurrency(result.baseHt);
  resultEls.fixedHt.textContent = result.fixedHt == null ? '—' : formatCurrency(result.fixedHt);
  resultEls.energyHt.textContent = result.energyHt == null ? '—' : formatCurrency(result.energyHt);
  resultEls.extraHt.textContent = result.extraHt == null ? '—' : formatCurrency(result.extraHt);
  reasonList.innerHTML = '';
  result.reasons.forEach(r => { const li=document.createElement('li'); li.textContent=r; reasonList.appendChild(li); });
}

function resetAll() {
  parcelsNode.innerHTML='';
  addParcel();
  collapseResultSections();
  renderResult({ carrier:'—', badge:'manual', note:'Renseigne les colis puis lance le calcul.', transportTtc:null, sellerTtc:null, baseHt:null, fixedHt:null, energyHt:null, extraHt:null, actualWeight:0, chargeableWeight:0, reasons:['Pas encore de calcul.'] });
}

function updateServiceNote() {
  serviceNote.textContent = 'Domicile : DPD si possible, sinon bascule automatique vers GEODIS.';
}

function toast(text) {
  const node = document.getElementById('toast');
  node.textContent = text;
  node.classList.add('show');
  clearTimeout(window.__toastTimer);
  window.__toastTimer = setTimeout(()=>node.classList.remove('show'), 2400);
}

function openSearch(matches) {
  searchList.innerHTML = '';
  matches.slice(0,18).forEach(d => {
    const b = document.createElement('button');
    b.type='button';
    b.className='search-item';
    b.textContent=`${d.code} — ${d.name}`;
    b.addEventListener('click', ()=>selectDepartment(d.code));
    searchList.appendChild(b);
  });
  searchList.classList.toggle('is-open', matches.length > 0);
}
function closeSearch() { searchList.classList.remove('is-open'); }

searchInput.addEventListener('input', () => {
  const q = searchInput.value.trim().toLowerCase();
  if (!q) return closeSearch();
  const matches = departments.filter(d => d.code.toLowerCase().includes(q) || d.name.toLowerCase().includes(q));
  openSearch(matches);
});
searchInput.addEventListener('focus', () => {
  const q = searchInput.value.trim().toLowerCase();
  if (!q) return;
  const matches = departments.filter(d => d.code.toLowerCase().includes(q) || d.name.toLowerCase().includes(q));
  openSearch(matches);
});
document.addEventListener('click', (e) => { if (!searchList.contains(e.target) && e.target !== searchInput) closeSearch(); });
document.getElementById('resetSearch').addEventListener('click', () => { searchInput.value=''; closeSearch(); });
const focusVosgesBtn = document.getElementById('focusVosges');
if (focusVosgesBtn) focusVosgesBtn.addEventListener('click', () => selectDepartment('88'));

document.getElementById('addParcel').addEventListener('click', () => addParcel());
document.getElementById('calculateBtn').addEventListener('click', () => {
  try {
    const parcels = readParcels();
    renderResult(computeQuote(parcels));
  } catch (err) {
    toast(err.message || 'Impossible de calculer.');
  }
});
document.getElementById('resetBtn').addEventListener('click', resetAll);

renderMap();
selectDepartment('88');
updateServiceNote();
resetAll();